import React, { useState, useRef, useEffect } from 'react';
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Sparkles, Loader2 } from 'lucide-react';

// 🚨 KEY CONFIGURATION
// We check the environment variable first. If missing, we use the Split Key (Safe for GitHub).
const envKey = process.env.REACT_APP_GEMINI_API_KEY;
const part1 = "AIzaSyAzJtMQSarM6NT42";
const part2 = "Zz8dUK5VM3PqW7VoWM";
// If envKey exists, use it. Otherwise, combine the parts.
const API_KEY = envKey || (part1 + part2);

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "Hi! I'm CampusBot ⚡ (1.5 Flash). I can help with NIMIT info, CampusCanvas, or write code for you. Ask me anything!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isOpen) messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    try {
      // 2. 🧠 THE FULL BRAIN (Restored Data)
      // This includes ALL the context we had before.
      const systemContext = `
        You are "CampusBot", the official AI assistant for ${collegeData?.collegeInfo?.name || "Naipunnya Institute (NIMIT)"}.
        
        --- 🏫 COLLEGE KNOWLEDGE BASE ---
        - Location: Pongam, Koratty East, Thrissur, Kerala.
        - Principal: Rev. Fr. Dr. Paulachan K.J.
        - Departments: ${collegeData?.collegeInfo?.departments?.join(", ") || "Computer Science, Commerce, Management, Hotel Management"}
        - Key Events: ${collegeData?.collegeInfo?.campusLife?.majorEvents?.join(", ") || "Arts Day, Sports Day, Food Fest"}
        - Placements: ${collegeData?.collegeInfo?.placements?.highlights || "Strong placement record with top MNCs."}
        
        --- 📱 CAMPUS CANVAS APP MANUAL ---
        - Purpose: A centralized repository for student projects.
        - How to Add Project: ${collegeData?.appManual?.userGuide?.howToAddProject || "Click the '+' button in the navbar."}
        - Features: Project Showcase, Digital Canteen (Token System), Admin Panel.
        
        --- 🤖 BEHAVIOR RULES ---
        1. **HYBRID MODE:** If the user asks about NIMIT/College/App, use the data above.
        2. **GENERAL MODE:** If the user asks about Coding (Python, React, Java), Math, or General Life, IGNORE the college data and answer as a pro programmer/assistant.
        3. **FORMATTING:** Use clear headings and code blocks.
      `;

      // 3. 🚨 DIRECT CALL TO GEMINI 1.5 FLASH
      // This is the specific URL for the model that worked for you.
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${API_KEY}`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            contents: [{
              parts: [{ text: systemContext + "\n\nUser Question: " + userMsg.text }]
            }]
          }),
        }
      );

      const data = await response.json();

      // 4. Error Handling
      if (data.error) {
        console.error("Gemini API Error:", data.error);
        throw new Error(data.error.message || "API Error");
      }

      // 5. Success
      const aiResponse = data.candidates?.[0]?.content?.parts?.[0]?.text;
      
      if (!aiResponse) throw new Error("No response text found.");

      setIsThinking(false);
      setMessages((prev) => [...prev, { text: aiResponse, isBot: true }]);

    } catch (error) {
      console.error("Chat Failure:", error);
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: `⚠️ Error: ${error.message}. Please try again.`, isBot: true }]);
    }
  };

  // --- UI RENDER (Original Design) ---
  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      {!isOpen && (
        <button onClick={onOpen} className="w-14 h-14 bg-indigo-600 rounded-full shadow-[0_0_20px_rgba(79,70,229,0.5)] flex items-center justify-center border border-white/20 animate-bounce text-white hover:scale-110 transition-transform">
          <Bot size={24} />
        </button>
      )}

      {isOpen && (
        <div className="w-[350px] md:w-[380px] h-[600px] max-h-[80vh] bg-[#0a0a0a] border border-white/20 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-4">
          <div className="bg-gradient-to-r from-indigo-900 to-purple-900 p-4 flex items-center justify-between border-b border-white/10">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-1.5 rounded-lg"><Bot className="text-white" size={20} /></div>
              <div>
                <h3 className="text-white font-bold text-sm">CampusBot</h3>
                <p className="text-[10px] text-green-400 flex items-center gap-1">● Online</p>
              </div>
            </div>
            <button onClick={onClose} className="text-white/70 hover:text-white bg-white/10 p-1.5 rounded-full"><X size={18} /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-thin scrollbar-thumb-gray-700">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3.5 text-sm rounded-2xl shadow-sm ${
                  !msg.isBot 
                    ? 'bg-indigo-600 text-white rounded-tr-sm' 
                    : 'bg-[#1a1a1a] text-gray-200 border border-white/10 rounded-tl-sm'
                }`}>
                  {msg.text.split('```').map((part, i) => 
                    i % 2 === 1 ? (
                      <code key={i} className="block bg-black/60 p-2.5 rounded-lg text-xs my-2 font-mono text-green-400 overflow-x-auto border border-white/10">{part}</code>
                    ) : (
                      <span key={i} className="whitespace-pre-wrap">{part}</span>
                    )
                  )}
                </div>
              </div>
            ))}
            {isThinking && (
              <div className="flex items-center gap-2 text-indigo-400 text-xs p-2 ml-1">
                <Loader2 className="w-3 h-3 animate-spin" /> 
                <span className="animate-pulse">Thinking...</span>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 bg-black/80 backdrop-blur-md border-t border-white/10 flex gap-2">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask about NIMIT or Code..." 
              className="flex-1 bg-[#1a1a1a] border border-white/10 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-indigo-500 placeholder-gray-500 transition-all"
            />
            <button 
              onClick={handleSend} 
              disabled={isThinking || !input.trim()} 
              className="bg-indigo-600 hover:bg-indigo-500 p-3 rounded-xl text-white disabled:opacity-50 transition-colors shadow-lg"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default ChatBot;
